void LcdDisplay::SetChatMessage(const char *role, const char *content)
{
    DisplayLockGuard lock(this);

    // Don't display empty messages
    if (content == nullptr || content[0] == '\0') {
        return;
    }

    // Remove AI logo when showing non-system messages
    if (strcmp(role, "system") != 0 && emoji_label_ != nullptr) {
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create a new message bubble
    lv_obj_t *msg_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(msg_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(msg_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(msg_bubble, 0, 0);
    lv_obj_set_style_pad_all(msg_bubble, 8, 0);
    lv_obj_set_style_flex_grow(msg_bubble, 0, 0);

    // Determine message type and apply appropriate styling
    const char *bubble_type = "assistant";
    if (strcmp(role, "user") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, current_theme_->user_bubble_color(), 0);
        bubble_type = "user";
    } else if (strcmp(role, "system") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, current_theme_->system_bubble_color(), 0);
        bubble_type = "system";
    } else {
        lv_obj_set_style_bg_color(msg_bubble, current_theme_->assistant_bubble_color(), 0);
        bubble_type = "assistant";
    }

    // Set custom attribute to mark bubble type
    lv_obj_set_user_data(msg_bubble, (void *)bubble_type);

    // Create label for message content
    lv_obj_t *msg_label = lv_label_create(msg_bubble);
    lv_label_set_text(msg_label, content);
    lv_obj_set_width(msg_label, LV_HOR_RES * 0.75); // Limit width to 75% of screen

    // Set text alignment based on message type
    if (strcmp(role, "user") == 0) {
        lv_obj_set_style_text_align(msg_label, LV_TEXT_ALIGN_RIGHT, 0);
        lv_obj_align(msg_label, LV_ALIGN_RIGHT_MID, 0, 0);
    } else {
        lv_obj_set_style_text_align(msg_label, LV_TEXT_ALIGN_LEFT, 0);
        lv_obj_align(msg_label, LV_ALIGN_LEFT_MID, 0, 0);
    }

    // Set text color based on message type
    if (strcmp(role, "system") == 0) {
        lv_obj_set_style_text_color(msg_label, current_theme_->system_text_color(), 0);
    } else {
        lv_obj_set_style_text_color(msg_label, current_theme_->text_color(), 0);
    }

    // Set label properties
    lv_label_set_long_mode(msg_label, LV_LABEL_LONG_WRAP);
    lv_obj_set_style_text_font(msg_label, current_theme_->text_font()->font(), 0);

    // Align bubble based on message type
    if (strcmp(role, "user") == 0) {
        lv_obj_align(msg_bubble, LV_ALIGN_RIGHT_MID, 0, 0);
    } else {
        lv_obj_align(msg_bubble, LV_ALIGN_LEFT_MID, 0, 0);
    }

    // Remove oldest messages if we've reached the limit
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    if (child_count > MAX_MESSAGES) {
        // Remove the first child (oldest message)
        lv_obj_t *first_child = lv_obj_get_child(content_, 0);
        if (first_child != nullptr) {
            lv_obj_del(first_child);
        }
    }

    // Scroll to the latest message
    lv_obj_scroll_to_view_recursive(msg_bubble, LV_ANIM_ON);
}

