std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        return "{}";
    }

    // Create the payload structure
    cJSON *root = cJSON_CreateObject();
    if (root == NULL)
    {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

    // Generate HMAC-SHA256 signature
    std::string message = serial_number_ + activation_challenge_;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware-backed HMAC
    uint8_t hmac[32]; // SHA256 produces 32 bytes
    esp_err_t err = esp_hmac_calculate(ESP_HMAC_SHA256, (const uint8_t*)message.data(), message.length(), 
                                       (const uint8_t*)"device_activation_key", 21, hmac);
    if (err == ESP_OK)
    {
        // Convert HMAC to hex string
        std::string signature;
        signature.reserve(64);
        for (int i = 0; i < 32; i++)
        {
            char hex[3];
            snprintf(hex, sizeof(hex), "%02x", hmac[i]);
            signature += hex;
        }
        cJSON_AddStringToObject(root, "signature", signature.c_str());
    }
    else
    {
        ESP_LOGE(TAG, "Failed to calculate HMAC: %s", esp_err_to_name(err));
        cJSON_Delete(root);
        return "{}";
    }
#else
    // Fallback: use a simple hash or empty signature if hardware HMAC not supported
    ESP_LOGW(TAG, "Hardware HMAC not supported, using empty signature");
    cJSON_AddStringToObject(root, "signature", "");
#endif

    // Convert to string
    char *json_string = cJSON_Print(root);
    if (json_string == NULL)
    {
        cJSON_Delete(root);
        return "{}";
    }

    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

